rdf:RDF.dcat:Catalog:
		{% for locale in h.get_available_locales() -%}
		{{ catalog_title[locale.short_name] }}
		{% endfor -%}
		{% for locale in h.get_available_locales() -%}
		{{ catalog_desc[locale.short_name] }}
		{% endfor -%}

        {{ site_url }}federador.rdf
        {{ date_created }}Z
        {{ date_modified }}Z







		{% for package in packages -%}


				{% for locale in h.get_available_locales() -%}
					{% if package.title_translated[locale.short_name] -%}
					{{ package.title_translated[locale.short_name] }}
					{%- endif %}
				{% endfor -%}
				{% for locale in h.get_available_locales() -%}
					{% if package.notes_translated[locale.short_name] -%}
					{{ package.notes_translated[locale.short_name] }}
					{%- endif %}
				{% endfor -%}
				{% if package.organization.tematica_nti -%}

				{% elif package.organization.name -%}

				{% endif -%}
                {% if (package.organization.name == 'transport' ) -%}

                {% elif (package.organization.name == 'medi-ambient' ) -%}

                {% elif (package.organization.name == 'comerc' ) -%}

                {% elif (package.organization.name == 'ocupacio' ) -%}

                {% elif (package.organization.name == 'sector-public' ) -%}

                {% elif (package.organization.name == 'contractacio' ) -%}

                {% elif (package.organization.name == 'recursos-humans' ) -%}

                {% endif -%}
                {% if package.dades_alt_valor and package.dades_alt_valor != 'No' -%}

                    {% if (package.dades_alt_valor == 'Geoespacial' ) -%}

                    {% elif (package.dades_alt_valor == 'Observacio_de_la_Terra_i_medi_ambient' ) -%}

                    {% elif (package.dades_alt_valor == 'Meteorologia' ) -%}

                    {% elif (package.dades_alt_valor == 'Estadistica' ) -%}

                    {% elif (package.dades_alt_valor == 'Societats_i_propietat_de_societats' ) -%}

                    {% else -%}

                    {% endif -%}
                {% endif -%}
				{% for tag in package.tags -%}
					{% set safe_tag = _(tag.name).replace("'", " ") -%}
					{{ safe_tag }}
				{% endfor -%}


                {{ site_url }}dataset/{{ package.name }}

					{%- if package.fecha_publicacion -%}
						{{ h.publish_date_isoformat(package.fecha_publicacion) }}Z
					{%- else -%}
						{{ package.metadata_created }}Z
					{%- endif -%}

				{% if package.frequency 
					and not (package.frequency == 'PETICIO_ALCALDIA') 
					and not (package.frequency == 'PETICIO_NEGOCI') 
					and not (package.frequency == 'SERIE_INTERROMPUDA') 
					and not (package.frequency == 'NOT_ESPECIFIED') 
					and not (package.frequency == 'IMMEDIATA') -%}


                        {{ _(package.frequency) }}


                                {{ _(package.frequency) }}
								{% if package.frequency == 'CINC_MINUTS' -%}
									5
								{% elif package.frequency == 'TRENTA_MINUTS' -%}
									30
								{% elif package.frequency == 'UNA_HORA' -%}
									1
								{% elif package.frequency == 'DIARIA' -%}
									1
								{% elif package.frequency == 'SETMANAL' -%}
									1
								{% elif package.frequency == 'MENSUAL' -%}
									1
								{% elif package.frequency == 'BIMESTRAL' -%}
									2
								{% elif package.frequency == 'TRIMESTRAL' -%}
									3
								{% elif package.frequency == 'SEMESTRAL' -%}
									6
								{% elif package.frequency == 'ANUAL' -%}
									1
								{% elif package.frequency == 'BIENNAL' -%}
									2
								{% elif package.frequency == 'QUINQUENNAL' -%}
									5
								{% elif package.frequency == 'DECENAL' -%}
									10
							{% endif -%}




				{% endif -%}





                {% for locale in h.get_available_locales() -%}
                {{ site_url }}{{ locale.short_name }}/dataset/{{ package.name }}
                {% endfor -%}


                        {%- if package.fuente -%}{{ package.fuente }}{% else -%}Ajuntament de Barcelona{% endif -%}
                        {%- if package.department -%}{{ package.department }}{% endif -%}

                        {%- if package.maintainer_email -%}{% endif -%}
                        {%- if package.maintainer_tel -%}{% endif -%}





                        {%- if package.created -%}{{ package.created }}{% else -%}2016-01-01T00:00:00Z{% endif -%}
                        {%- if package.updated -%}{{ package.updated }}{% else -%}2025-11-01T00:00:00Z{% endif -%}


				{% for resource in package.resources -%}


                        {{ site_url }}dataset/{{ package.name }}/resource/{{ resource.id }}
						{% for locale in h.get_available_locales() -%}
							{{ resource.name }}
						{% endfor -%}
                        {% for locale in h.get_available_locales() -%}
                            {{ catalog_desc[locale.short_name] }}
                        {% endfor -%}


                        {%- if resource.size -%}{{ resource.size }}{% endif -%}




                                {{ h.get_mimetype(resource) }}
                                {{ resource.format }}




				{% endfor -%}


		{% endfor -%}
